import React, { useEffect, useState } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate, Outlet, useNavigate } from 'react-router-dom';
import { ToastContainer } from 'react-toastify';
import { AuthProvider } from './context/AuthContext';
import { RecordsProvider, useRecords } from './context/RecordsContext';
import ProtectedRoute from './components/auth/ProtectedRoute';
import LoginScreen from './components/auth/LoginScreen';
import RegisterScreen from './components/auth/RegisterScreen';
import Dashboard from './components/dashboard/Dashboard';
import RecordsPortal from './components/records/RecordsPortal';
import NewEvaluation from './components/records/NewEvaluation';
import Sidebar from './components/layout/Sidebar';
import { useAuth } from './hooks/useAuth';
import { initSocket, disconnectSocket } from './services/socket';
import 'react-toastify/dist/ReactToastify.css';
import './App.css';

function App() {
  return (
    <Router>
      <AuthProvider>
        <RecordsProvider>
          <AppShell />
        </RecordsProvider>
      </AuthProvider>
    </Router>
  );
}

function AppShell() {
  const [online, setOnline] = useState(navigator.onLine);

  useEffect(() => {
    const handleOnline = () => setOnline(true);
    const handleOffline = () => setOnline(false);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, []);

  useEffect(() => {
    if (online) {
      initSocket();
    } else {
      disconnectSocket();
    }
  }, [online]);

  return (
    <div className="min-h-screen bg-slate-50">
      {!online && (
        <div className="bg-yellow-500 text-white text-center py-2 fixed top-0 left-0 right-0 z-50">
          You are offline. Changes will sync when connection is restored.
        </div>
      )}

      <Routes>
        <Route path="/login" element={<LoginPage />} />
        <Route path="/register" element={<RegisterPage />} />
        <Route element={<ProtectedRoute />}>
          <Route element={<AppLayout />}>
            <Route path="/" element={<Navigate to="/dashboard" replace />} />
            <Route path="/dashboard" element={<DashboardPage />} />
            <Route path="/records" element={<RecordsPage />} />
            <Route path="/new-evaluation" element={<NewEvaluationPage />} />
          </Route>
        </Route>
      </Routes>

      <ToastContainer
        position="top-right"
        autoClose={5000}
        hideProgressBar={false}
        newestOnTop
        closeOnClick
        rtl={false}
        pauseOnFocusLoss
        draggable
        pauseOnHover
      />
    </div>
  );
}

function LoginPage() {
  const { isAuthenticated, login } = useAuth();

  if (isAuthenticated) {
    return <Navigate to="/dashboard" replace />;
  }

  return <LoginScreen onLogin={login} />;
}

function RegisterPage() {
  const { isAuthenticated } = useAuth();

  if (isAuthenticated) {
    return <Navigate to="/dashboard" replace />;
  }

  return <RegisterScreen />;
}

function AppLayout() {
  const { user, logout } = useAuth();

  return (
    <div className="app-shell">
      <Sidebar user={user} onLogout={logout} />
      <main className="app-main">
        <Outlet />
      </main>
    </div>
  );
}

function DashboardPage() {
  const { user } = useAuth();
  const { records, refreshRecords } = useRecords();

  return <Dashboard records={records} user={user} onRefresh={refreshRecords} />;
}

function RecordsPage() {
  const { user } = useAuth();
  const { records, refreshRecords, updateRecord, deleteRecord } = useRecords();

  return (
    <RecordsPortal
      records={records}
      user={user}
      onUpdate={updateRecord}
      onDelete={deleteRecord}
      onRefresh={refreshRecords}
    />
  );
}

function NewEvaluationPage() {
  const navigate = useNavigate();
  const { createRecord } = useRecords();

  const handleSubmit = async (recordData) => {
    await createRecord(recordData);
    navigate('/records');
  };

  return <NewEvaluation onSubmit={handleSubmit} onCancel={() => navigate('/records')} />;
}

export default App;
